head.script:
(function (w, d, s, l, i) {
  w[ l ] = w[ l ] || [];
  w[ l ].push({
    'gtm.start': new Date().getTime(), event: 'gtm.js'
  });
  var f = d.getElementsByTagName(s)[ 0 ],
    j = d.createElement(s), dl = l != 'dataLayer' ? '&l=' + l : '';
  j.async = true;
  j.src = 'https://www.googletagmanager.com/gtm.js?id=' + i + dl;
  f.parentNode.insertBefore(j, f);
})(window, document, 'script', 'dataLayer', 'GTM-WHH7MGW');

div.script:
	const quickHelp = document.getElementById('quick-help');
  quickHelp.addEventListener('click', event => {
  	    event.preventDefault();
   	window?.Intercom('show');  
  })

body.script:
    window.dataLayer = window.dataLayer || [];
  function gtag(){dataLayer.push(arguments);}
  gtag('consent', 'default', {
  'ad_storage': 'denied',
  'ad_user_data': 'denied',
  'ad_personalization': 'denied',
  'analytics_storage': 'denied'
});
 // window.intercomSettings = { 
     // api_base: "https://api-iam.intercom.io", 
    // app_id: "x1mf39c9", 
    // name: 'Website Visitor' 
  // };

  window.dataLayer = window.dataLayer || [];
function gtag(){dataLayer.push(arguments);}

gtag('js', new Date());
gtag('config', 'G-YR26QNHTFN');

      window.addEventListener('load', function(){

          // obtain plugin
          var cc = initCookieConsent();

          // run plugin with your configuration
          cc.run({
              current_lang: 'en',
              autoclear_cookies: true,                   // default: false
              page_scripts: true,                        // default: false

              // mode: 'opt-in'                          // default: 'opt-in'; value: 'opt-in' or 'opt-out'
              // delay: 0,                               // default: 0
              // auto_language: '',                      // default: null; could also be 'browser' or 'document'
              // autorun: true,                          // default: true
              // force_consent: false,                   // default: false
              // hide_from_bots: false,                  // default: false
              // remove_cookie_tables: false             // default: false
              // cookie_name: 'cc_cookie',               // default: 'cc_cookie'
              // cookie_expiration: 182,                 // default: 182 (days)
              // cookie_necessary_only_expiration: 182   // default: disabled
              // cookie_domain: location.hostname,       // default: current domain
              // cookie_path: '/',                       // default: root
              // cookie_same_site: 'Lax',                // default: 'Lax'
              // use_rfc_cookie: false,                  // default: false
              // revision: 0,                            // default: 0

              onFirstAction: function(user_preferences, cookie){
                  // callback triggered only once on the first accept/reject action
              },

              onAccept: function (cookie) {
                  // callback triggered on the first accept/reject action, and after each page load

                 if(cookie.categories.includes('analytics')) {
        gtag('consent', 'update', {
          'ad_storage': 'granted',
          'analytics_storage': 'granted',
            'ad_user_data': 'granted',
'ad_personalization': 'granted',
        });
      } else {
        gtag('consent', 'update', {
          'ad_storage': 'denied',
          'analytics_storage': 'denied',
          'ad_personalization': 'denied',
'analytics_storage': 'denied'
        });
      }
              },

              onChange: function (cookie, changed_categories) {
                  // callback triggered when user changes preferences after consent has already been given
                 if(changed_categories.includes('analytics')) {
        gtag('consent', 'update', {
          'ad_storage': 'granted',
          'analytics_storage': 'granted',
                        'ad_user_data': 'granted',
'ad_personalization': 'granted',
        });
      } else {
        gtag('consent', 'update', {
          'ad_storage': 'denied',
          'analytics_storage': 'denied',
            'ad_personalization': 'denied',
'analytics_storage': 'denied'
        });
      }
              },

              languages: {
                  'en': {
                      consent_modal: {
                          title: 'We use cookies!',
                          description: 'Cookies help us improve our services. Please review our cookies  policy.',
                          primary_btn: {
                              text: 'Accept Cookies',
                              role: 'accept_all'              // 'accept_selected' or 'accept_all'
                          },
                          secondary_btn: {
                              text: 'Essential Cookies Only',
                              role: 'accept_necessary'        // 'settings' or 'accept_necessary'
                          }
                      },
                      settings_modal: {
                          title: 'Cookie preferences',
                          save_settings_btn: 'Save settings',
                          accept_all_btn: 'Accept all',
                          reject_all_btn: 'Reject all',
                          close_btn_label: 'Close',
                          cookie_table_headers: [
                              {col1: 'Name'},
                              {col2: 'Domain'},
                              {col3: 'Expiration'},
                              {col4: 'Description'}
                          ],
                          blocks: [
                              {
                                  title: 'Cookie usage 📢',
                                  description: 'I use cookies to ensure the basic functionalities of the website and to enhance your online experience. You can choose for each category to opt-in/out whenever you want. For more details relative to cookies and other sensitive data, please read the full privacy policy.'
                              }, {
                                  title: 'Strictly necessary cookies',
                                  description: 'These cookies are essential for the proper functioning of my website. Without these cookies, the website would not work properly',
                                  toggle: {
                                      value: 'necessary',
                                      enabled: true,
                                      readonly: true          // cookie categories with readonly=true are all treated as "necessary cookies"
                                  }
                              }, {
                                  title: 'Performance and Analytics cookies',
                                  description: 'These cookies allow the website to remember the choices you have made in the past',
                                  toggle: {
                                      value: 'analytics',     // your cookie category
                                      enabled: false,
                                      readonly: false
                                  },
                                  cookie_table: [             // list of all expected cookies
                                      {
                                          col1: '^_ga',       // match all cookies starting with "_ga"
                                          col2: 'google.com',
                                          col3: '2 years',
                                          col4: 'description ...',
                                          is_regex: true
                                      },
                                      {
                                          col1: '_gid',
                                          col2: 'google.com',
                                          col3: '1 day',
                                          col4: 'description ...',
                                      }
                                  ]
                              }, {
                                  title: 'Advertisement and Targeting cookies',
                                  description: 'These cookies collect information about how you use the website, which pages you visited and which links you clicked on. All of the data is anonymized and cannot be used to identify you',
                                  toggle: {
                                      value: 'targeting',
                                      enabled: false,
                                      readonly: false
                                  }
                              }, {
                                  title: 'More information',
                                  description: 'For any queries in relation to our policy on cookies and your choices, please contact us.',
                              }
                          ]
                      }
                  }
              }
          });
      });
